import{_ as o,o as l,c as i,ai as a}from"./chunks/framework.ampVZV4B.js";const u=JSON.parse('{"title":"日常通用口语模板","description":"","frontmatter":{},"headers":[],"relativePath":"english-speaking/templates-daily.md","filePath":"english-speaking/templates-daily.md"}'),d={name:"english-speaking/templates-daily.md"};function c(t,e,r,n,h,s){return l(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="日常通用口语模板" tabindex="-1">日常通用口语模板 <a class="header-anchor" href="#日常通用口语模板" aria-label="Permalink to “日常通用口语模板”">​</a></h1><blockquote><p>这一篇优先解决“最常用、最容易开口”的日常表达。<br> 先背熟这些，再去扩展更复杂的场景。</p></blockquote><hr><h2 id="_1-打招呼-10-句" tabindex="-1">1. 打招呼（10 句） <a class="header-anchor" href="#_1-打招呼-10-句" aria-label="Permalink to “1. 打招呼（10 句）”">​</a></h2><ol><li><code>Hi, how are you?</code></li><li><code>How&#39;s it going?</code></li><li><code>Good morning.</code></li><li><code>Good afternoon.</code></li><li><code>Good evening.</code></li><li><code>Nice to see you.</code></li><li><code>Long time no see.</code></li><li><code>How have you been?</code></li><li><code>It&#39;s good to see you again.</code></li><li><code>Hope you&#39;re doing well.</code></li></ol><h2 id="_2-自我表达近况-8-句" tabindex="-1">2. 自我表达近况（8 句） <a class="header-anchor" href="#_2-自我表达近况-8-句" aria-label="Permalink to “2. 自我表达近况（8 句）”">​</a></h2><ol start="11"><li><code>I&#39;m doing well, thanks.</code></li><li><code>I&#39;ve been pretty busy lately.</code></li><li><code>Things are going well.</code></li><li><code>I&#39;m a little tired today.</code></li><li><code>I&#39;ve had a long day.</code></li><li><code>Everything is fine so far.</code></li><li><code>I&#39;m just taking it easy today.</code></li><li><code>I&#39;ve been learning a lot recently.</code></li></ol><h2 id="_3-表达感谢-8-句" tabindex="-1">3. 表达感谢（8 句） <a class="header-anchor" href="#_3-表达感谢-8-句" aria-label="Permalink to “3. 表达感谢（8 句）”">​</a></h2><ol start="19"><li><code>Thank you so much.</code></li><li><code>Thanks a lot.</code></li><li><code>I really appreciate it.</code></li><li><code>That means a lot to me.</code></li><li><code>Thanks for your help.</code></li><li><code>Thanks for your time.</code></li><li><code>I appreciate your support.</code></li><li><code>I&#39;m grateful for that.</code></li></ol><h2 id="_4-表达抱歉-8-句" tabindex="-1">4. 表达抱歉（8 句） <a class="header-anchor" href="#_4-表达抱歉-8-句" aria-label="Permalink to “4. 表达抱歉（8 句）”">​</a></h2><ol start="27"><li><code>I&#39;m sorry.</code></li><li><code>I&#39;m really sorry about that.</code></li><li><code>Sorry for the trouble.</code></li><li><code>Sorry I&#39;m late.</code></li><li><code>Sorry to keep you waiting.</code></li><li><code>I didn&#39;t mean to do that.</code></li><li><code>It was my mistake.</code></li><li><code>Please accept my apology.</code></li></ol><h2 id="_5-请求帮助-10-句" tabindex="-1">5. 请求帮助（10 句） <a class="header-anchor" href="#_5-请求帮助-10-句" aria-label="Permalink to “5. 请求帮助（10 句）”">​</a></h2><ol start="35"><li><code>Could you help me?</code></li><li><code>Could you help me with this?</code></li><li><code>Can you show me how to do this?</code></li><li><code>Would you mind helping me for a minute?</code></li><li><code>Can I ask you something?</code></li><li><code>Could you explain that again?</code></li><li><code>Can you give me an example?</code></li><li><code>Could you slow down a little?</code></li><li><code>Can you speak a bit more clearly?</code></li><li><code>Could you point me in the right direction?</code></li></ol><h2 id="_6-表达听不懂-8-句" tabindex="-1">6. 表达听不懂（8 句） <a class="header-anchor" href="#_6-表达听不懂-8-句" aria-label="Permalink to “6. 表达听不懂（8 句）”">​</a></h2><ol start="45"><li><code>I don&#39;t understand.</code></li><li><code>I didn&#39;t catch that.</code></li><li><code>Could you say that again?</code></li><li><code>Could you repeat that, please?</code></li><li><code>What do you mean by that?</code></li><li><code>I&#39;m not sure I follow.</code></li><li><code>Could you explain it in a simpler way?</code></li><li><code>Let me make sure I understand.</code></li></ol><h2 id="_7-表达喜欢-不喜欢-8-句" tabindex="-1">7. 表达喜欢 / 不喜欢（8 句） <a class="header-anchor" href="#_7-表达喜欢-不喜欢-8-句" aria-label="Permalink to “7. 表达喜欢 / 不喜欢（8 句）”">​</a></h2><ol start="53"><li><code>I like it.</code></li><li><code>I love it.</code></li><li><code>I&#39;m really into that.</code></li><li><code>That sounds great.</code></li><li><code>I&#39;m not a big fan of it.</code></li><li><code>It&#39;s not really my thing.</code></li><li><code>I don&#39;t like it that much.</code></li><li><code>I&#39;d rather do something else.</code></li></ol><h2 id="_8-结束对话-10-句" tabindex="-1">8. 结束对话（10 句） <a class="header-anchor" href="#_8-结束对话-10-句" aria-label="Permalink to “8. 结束对话（10 句）”">​</a></h2><ol start="61"><li><code>I have to go now.</code></li><li><code>Talk to you later.</code></li><li><code>See you soon.</code></li><li><code>See you next time.</code></li><li><code>Take care.</code></li><li><code>Have a nice day.</code></li><li><code>Have a good one.</code></li><li><code>It was nice talking to you.</code></li><li><code>Let&#39;s catch up again soon.</code></li><li><code>Bye for now.</code></li></ol><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to “使用建议”">​</a></h2><ul><li>先优先背 <code>35-52</code> 这组，它们最实用</li><li>每次挑 10 句，先读熟再替换关键词</li><li>把这些句子录音，反复听自己的发音</li></ul>',22)])])}const y=o(d,[["render",c]]);export{u as __pageData,y as default};
